import { createGlobalStyle } from 'styled-components';
import RubikRegular from './fonts/Rubik-Regular.ttf'
 
const GlobalStyle = createGlobalStyle`
  body {
    margin: 0;
    padding: 0;
    background: black;
  }

  ul {
    list-style: none;
  }

  @font-face {
    font-family: 'Rubik';
    src: url(${RubikRegular}) format('truetype');
    font-weight: 400;
  }
`;
 
export default GlobalStyle;
